<main class="container printable-confirmation"><section class="section"><h1>Golden Hour Events</h1><h2>Confirmación de reserva</h2><dl><dt>Código</dt><dd><?php echo htmlspecialchars($reservation['codigo_reserva'], ENT_QUOTES, 'UTF-8'); ?></dd><dt>Cliente</dt><dd><?php echo htmlspecialchars($reservation['cliente'], ENT_QUOTES, 'UTF-8'); ?></dd><dt>Evento</dt><dd><?php echo htmlspecialchars($reservation['evento'], ENT_QUOTES, 'UTF-8'); ?></dd><dt>Fecha</dt><dd><?php echo htmlspecialchars(date('d/m/Y H:i', strtotime($reservation['fecha_inicio'])), ENT_QUOTES, 'UTF-8'); ?></dd><dt>Lugar</dt><dd><?php echo htmlspecialchars($reservation['lugar'], ENT_QUOTES, 'UTF-8'); ?></dd><dt>Cantidad</dt><dd><?php echo (int) $reservation['cantidad']; ?></dd><dt>Total</dt><dd>S/ <?php echo formatMoney($reservation['monto_total']); ?></dd><dt>Estado</dt><dd>Confirmada</dd></dl><button class="btn btn-primary no-print" type="button" onclick="window.print()">Imprimir</button><a class="btn btn-outline no-print" href="<?php echo htmlspecialchars(base_url('views/client/reservation_detail.php?id=' . $id), ENT_QUOTES, 'UTF-8'); ?>">Volver</a></section></main><?php require __DIR__ . '/../../includes/footer.php'; ?>
